#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = 5*vUv;
uv1 = uv0;
d= length(uv1);

for ( int n=0; (n <10) && (n<14*d) ; n++ )
{
uv1 += sin(uv1.yx+par.yx) + uv0 - par;
d=fract(.1*length(uv1));
}

ret= d*vec3 (1, 1, 4);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = 0.5 + (vUv-0.5)*0.98;
    vec2 d = uTexSize.zw*4;
    vec3 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );
vec4 noise = texture3D(sampler_noisevol_hq, ((vUv.xyy+vec3(lum(dx),lum(dy),0)*0.5)*uTexSize.xyy*texsize_noisevol_hq.zww).xyz*vec3(1,1,0)*0.05
                                        + uTime*vec3(0,0,1)*0.2 );
vUv -= vec2(lum(dx),lum(dy))*0.04;
ret = abs(GetPixel(vUv)+GetBlur1(vUv)-GetBlur2(vUv)-GetBlur3(vUv));
ret *= lum(noise)*3;
ret = pow(ret,0.5);
vec2 uv2 = vUv*0.25;
vec3 col = 0;
vec2 uv3 = uv2;
for(int i = 0; i<16; i++){
    uv3 += i*vec2(0.25,0) - (0==(i)%4)*vec2(0,0.25);
    col = mix(col,i/16.0,mix(-GetPixel(uv3),tex2d(sampler_pw_main,fract(uv3)),.1));


}
reta = mix(GetPixel(vUv).z*vec3(0.6,0.2,1),vec3(1,1,1),col*clamp01(1-GetBlur1(vUv).x*2));
retb = mix(GetPixel(vUv).z*vec3(0.6,0.2,1),vec3(1,1,1),col*clamp01(1-GetBlur1(vUv).x*2));
    float gx = GetPixel(vUv+vec2(1,0)*uTexSize.zw) - GetPixel(vUv-vec2(1,0)*uTexSize.zw);
    float gy = GetPixel(vUv+vec2(0,1)*uTexSize.zw) - GetPixel(vUv-vec2(0,1)*uTexSize.zw);
    vec3 g = normalize(vec3(gx, gy, .04));

    reta = mix(ret,vec3(1.1,0.8,0.5),(dot(g.xyz,vec3(fract(vUv)-0.5,0.6))*0.5+0.5)*GetPixel(fract(vUv)).x);
    retb = mix(ret,vec3(1.1,0.8,0.5),(dot(g.xyz,vec3(fract(vUv)-0.5,0.6))*0.5+0.5)*GetPixel(fract(vUv)).x);
ret = mix(ret,reta,q20);
retc = mix(ret,retb,(roam_cos.x*10));
ret = mix(ret,retc,q20);
ret = 1 - ret;
ret *= audioHighSmooth * .2;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q3         && ret.x<= q23*q1        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q1         && ret.y<= q22*q2        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q2         && ret.z<= q21*q3        )ret.y -= (noise9).z*.5;

//MilkDrop3 Color Mode:
ret /= vec3(2.1,-1.7,0.2);

  fragColor = ret;
}
